import { MoreButton } from '@/components/more-button';
import { RAGFlowAvatar } from '@/components/ragflow-avatar';
import { useNavigatePage } from '@/hooks/logic-hooks/navigate-hooks';
import { IDialog } from '@/interfaces/database/chat';
import { cn } from '@/lib/utils';
import { MessageSquare, Settings2 } from 'lucide-react';
import styles from './chat-card.less';
import { ChatDropdown } from './chat-dropdown';
import { useRenameChat } from './hooks/use-rename-chat';

export type IProps = {
  data: IDialog;
} & Pick<ReturnType<typeof useRenameChat>, 'showChatRenameModal'>;

export function ChatCard({ data, showChatRenameModal }: IProps) {
  const { navigateToChat } = useNavigatePage();

  return (
    <article className={styles.card} onClick={navigateToChat(data?.id)}>
      <div className={styles.header}>
        <div className={styles.titleWrap}>
          <RAGFlowAvatar
            className={styles.avatar}
            avatar={data.icon}
            name={data.name}
          />
          <div className={styles.titleContent}>
            <div className={styles.title}>{data.name}</div>
          </div>
        </div>
      </div>

      <p className={styles.description}>
        {data.description || '用于知识库问答与内容检索的智能应用'}
      </p>

      <div className={styles.footer}>
        <div className={styles.tools}>
          <span className={styles.toolItem}>
            <MessageSquare className={cn('size-3.5', styles.toolIcon)} />
          </span>
          <span className={styles.toolItem}>
            <Settings2 className={cn('size-3.5', styles.toolIcon)} />
          </span>
        </div>
        <div
          className={styles.moreWrapper}
          onClick={(event) => {
            event.stopPropagation();
          }}
        >
          <ChatDropdown chat={data} showChatRenameModal={showChatRenameModal}>
            <MoreButton className={styles.moreButton} />
          </ChatDropdown>
        </div>
      </div>
    </article>
  );
}
