import { RenameDialog } from '@/components/rename-dialog';
import { SearchInput } from '@/components/ui/input';
import { RAGFlowPagination } from '@/components/ui/ragflow-pagination';
import { useFetchDialogList } from '@/hooks/use-chat-request';
import { pick } from 'lodash';
import { Plus } from 'lucide-react';
import { useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { ChatCard } from './chat-card';
import { useRenameChat } from './hooks/use-rename-chat';
import styles from './index.less';

export default function ChatList() {
  const { data, setPagination, pagination, handleInputChange, searchString } =
    useFetchDialogList();
  const { t } = useTranslation();
  const {
    initialChatName,
    chatRenameVisible,
    showChatRenameModal,
    hideChatRenameModal,
    onChatRenameOk,
    chatRenameLoading,
  } = useRenameChat();

  const handlePageChange = useCallback(
    (page: number, pageSize?: number) => {
      setPagination({ page, pageSize });
    },
    [setPagination],
  );

  const handleShowCreateModal = useCallback(() => {
    showChatRenameModal();
  }, [showChatRenameModal]);

  return (
    <section className={styles.page}>
      <div className={styles.filterRow}>
        <SearchInput
          value={searchString}
          onChange={handleInputChange}
          className={styles.searchInput}
          placeholder={t('chat.searchChatApp', {
            defaultValue: '搜索应用',
          })}
        />
      </div>
      <div className={styles.contentArea}>
        <div className={styles.cardGrid}>
          <article
            className={styles.createHintCard}
            onClick={handleShowCreateModal}
          >
            <div className={styles.createHintInner}>
              <span className={styles.createHintIconBox}>
                <Plus className="size-3.5" />
              </span>
              <span className={styles.createHintText}>
                {t('chat.createChat', { defaultValue: '创建应用' })}
              </span>
            </div>
          </article>
          {data.dialogs.map((x) => {
            return (
              <ChatCard
                key={x.id}
                data={x}
                showChatRenameModal={showChatRenameModal}
              ></ChatCard>
            );
          })}
        </div>
      </div>
      <div className={styles.paginationRow}>
        <RAGFlowPagination
          {...pick(pagination, 'current', 'pageSize')}
          total={pagination.total}
          onChange={handlePageChange}
        ></RAGFlowPagination>
      </div>
      {chatRenameVisible && (
        <RenameDialog
          hideModal={hideChatRenameModal}
          onOk={onChatRenameOk}
          initialName={initialChatName}
          loading={chatRenameLoading}
          title={initialChatName || t('chat.createChat')}
        ></RenameDialog>
      )}
    </section>
  );
}
